import{_ as t,o as r,c as s,ae as o}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Handle Data Subject Requests From End Users","description":"","frontmatter":{"title":"Handle Data Subject Requests From End Users","slug":"handling-data-subject-requests-from-end-users"},"headers":[],"relativePath":"account-hub/handling-data-subject-requests-from-end-users.md","filePath":"account-hub/handling-data-subject-requests-from-end-users.md"}'),i={name:"account-hub/handling-data-subject-requests-from-end-users.md"};function a(n,e,l,u,c,d){return r(),s("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This documentation contains information on the procedure for submitting data subject requests to Branch for your end users, to support you in your compliance efforts with applicable data protection laws like GDPR. When your end users exercise their rights under applicable data protection laws, Branch is committed to working with you to fulfill these requests, provided the request comes directly from you. The purpose of this document is to outline the process in which you &amp; Branch will coordinate to facilitate data subject requests for your end users.</p><h2 id="branch-data-subject-deletion-request-process" tabindex="-1">Branch Data Subject Deletion Request Process <a class="header-anchor" href="#branch-data-subject-deletion-request-process" aria-label="Permalink to &quot;Branch Data Subject Deletion Request Process&quot;">​</a></h2><ul><li><p><strong>Construct a batched request in .CSV file format for all outstanding data deletion requests which contains the following information and adhere</strong> <a href="https://cdn.us.document360.io/082e8be0-ad38-4650-9062-689a75e517a2/Images/Documentation/gdpr-request-template.xlsx" target="_blank" rel="noreferrer"><strong>to this file format</strong></a> <strong>(&quot;Data Subject Deletion Request Template&quot;).</strong></p><ul><li><p><strong>device_id</strong> - an ID pertaining to the end user’s device. This could be a number of different identifiers depending on the user’s device type (e.g. IDFA, GAID, IDFV, AAID, MAC address, Roku RIDA, Fire Ad ID, etc.)</p><ul><li>Note: In the event IDFA is unavailable due to iOS 14 updates, Branch will only be able to process the respective data subject request if you provide a secondary identifier like IDFV or developer_id.</li></ul></li><li><p><strong>developer_id</strong> - an ID set by you. This is a way for you to identify your users using your own convention (e.g. unique alphanumeric ID, etc.)</p></li><li><p><strong>browser_id</strong> - also known as browser_fingerprint_id, which is a unique ID created by Branch to identify a specific browser</p></li><li><p><strong>user_id</strong> - an ID set by you. This is a way for you to identify your users using your own naming convention (e.g. unique alphanumeric ID, etc.)</p></li></ul></li><li><p><strong>Submit the batched request through our Data Subject Request Portal:</strong></p><ul><li><p>Visit the Branch Privacy Center and fill out the Deletion Request<a href="https://preferences.branch.io/form/deletion" target="_blank" rel="noreferrer">form</a>.</p></li><li><p><strong>Required Fields:</strong></p><ul><li><p><strong>Email Address</strong>: your email address</p></li><li><p><strong>Requestor</strong>: Select “Someone else’s behalf”</p></li><li><p><strong>Request Type:</strong> Select &quot;Data Deletion&quot;</p></li><li><p><strong>Original Request Date</strong>: Input date of submission</p></li><li><p><strong>Subject</strong>: &quot;[Your company Name] - Deletion request - [MM/DD/YYYY]&quot;</p></li><li><p><strong>Description</strong>: &quot;Requesting data deletion request for the list of attached IDs.&quot;</p><ul><li>Please Include your App ID. <em>see below Security/Request Validation</em></li></ul></li><li><p><strong>Attachments</strong>: upload .CSV file</p></li></ul></li></ul></li><li><p><strong>Security/Request Validation:</strong></p><ul><li><p>If it is the first time Branch has received a data subject request from you, we will need to validate the request for security purposes and ask that you provide the following information to carry out the request:</p><ul><li>Your Branch App ID(s) for the app(s) at issue (available under <strong>Account &gt; Settings &gt; Profile</strong> in <a href="./branch-dashboard-overview.html">legacy Branch</a> or under <strong>Configuration &gt; App Settings &gt; General</strong> in <a href="./new-branch-overview.html">new Branch</a>);</li><li>Please copy in your reply at least one person who is listed as an admin on the app&#39;s Branch account, and have each admin reply-all to confirm that the request should be executed</li></ul></li></ul></li><li><p><strong>Branch’s Privacy Team</strong> will confirm completion via email.</p><ul><li><strong>Please note that you should expect a confirmation within 7-14 business days from submission time</strong></li></ul></li></ul><h2 id="branch-data-subject-access-request-process" tabindex="-1">Branch Data Subject Access Request Process <a class="header-anchor" href="#branch-data-subject-access-request-process" aria-label="Permalink to &quot;Branch Data Subject Access Request Process&quot;">​</a></h2><ul><li><p><strong>Construct a batched request for all outstanding data access requests which contains the following information and adheres to</strong> <a href="https://cdn.us.document360.io/082e8be0-ad38-4650-9062-689a75e517a2/Images/Documentation/gdpr-request-template.xlsx" target="_blank" rel="noreferrer"><strong>this file format</strong></a> <strong>(&quot; Data Subject Access Request Template&quot;)</strong></p><ul><li><p><strong>device_id</strong> - an ID pertaining to the end user’s device. This could be a number of different identifiers depending on the user’s device type (e.g. IDFA, GAID, IDFV, AAID, MAC address, etc)</p><ul><li>Note: In the event IDFA is unavailable due to iOS 14 updates, Branch will only be able to process the respective data subject request if you provide a secondary identifier like IDFV or developer_id.</li></ul></li><li><p><strong>developer_id</strong> - an ID set by you. This is a way for you to identify your users using your own convention (e.g. unique alphanumeric ID, etc)</p></li><li><p><strong>browser_id</strong> - also known as browser_fingerprint_id, which is a unique ID created by Branch to identify a specific browser</p></li><li><p><strong>user_id</strong> - an ID set by you. This is a way for you to identify your users using your own naming convention (e.g. unique alphanumeric ID, etc)</p></li></ul></li><li><p><strong>Submit a Request through our Data Subject Request Portal:</strong></p><ul><li><p>Visit the Branch Privacy Center and fill out the Deletion Request<a href="https://preferences.branch.io/form/deletion" target="_blank" rel="noreferrer">form</a>.</p></li><li><p><strong>Required Fields:</strong></p><ul><li><p><strong>Email Address</strong>: your email address/alias</p></li><li><p><strong>Requestor</strong> Select “Someone else’s behalf”</p></li><li><p><strong>Request Type:</strong> Select &quot;Access to Data&quot;</p></li><li><p><strong>Original Request Date</strong>: Input date of submission</p></li><li><p><strong>Subject</strong>: &quot;[Your company Name] - Data Access Request - [MM/DD/YYYY]&quot;</p></li><li><p><strong>Description</strong>: &quot;Requesting data on the list of attached IDs.&quot;</p><ul><li>Please Include your App ID. <em>see below Security/Request Validation</em></li></ul></li><li><p><strong>Attachments</strong>: upload .CSV file</p></li></ul></li></ul></li><li><p><strong>Security/ Request Validation:</strong></p><ul><li><p>If it is the first time we have received a data subject request from you, we ask that you provide the following information to carry out the request (and for security reasons):</p><ul><li>Your Branch App ID(s) for the app(s) at issue (available under <strong>Account &gt; Settings &gt; Profile</strong> in <a href="./branch-dashboard-overview.html">legacy Branch</a> or under <strong>Configuration &gt; App Settings &gt; General</strong> in <a href="./new-branch-overview.html">new Branch</a>);</li><li>Please copy in your reply at least one person who is listed as an admin on the app&#39;s Branch account, and have each admin reply-all to confirm that the request should be executed</li></ul></li></ul></li><li><p><strong>Branch’s Privacy Team will confirm completion of executing the request via email</strong></p><ul><li><p><strong>Please note that you should expect a confirmation within 7-14 business days from submission time</strong></p><ul><li><strong>NOTE: If applicable law requires a prompter response, please contact us at</strong> <a href="mailto:privacy@branch.io" target="_blank" rel="noreferrer"><strong>privacy@branch.io</strong></a><strong>.</strong></li></ul></li><li><p>Branch will provide you with a file that contains the end user’s personal data subject to the request</p></li><li><p>File Details:</p><ul><li>There will be one output file per submission request</li><li><strong>Status:</strong> if Branch possesses personal data for the end user status will be 200; if not it will be 400</li><li><strong>URL</strong>: if Branch possesses personal data for a particular end user subject to the data access request, the file will contain a URL for which the end user can click and a separate JSON file can be opened in browser. The generated report is available for seven days from the time of completion of the request.</li></ul></li></ul></li></ul>',6)])])}const g=t(i,[["render",a]]);export{h as __pageData,g as default};
